import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"工作流和模板区别","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/workflow-vs-template.md","filePath":"workflows/workflow-vs-template.md","lastUpdated":1782223980000}'),o={name:"workflows/workflow-vs-template.md"};function r(n,l,s,h,p,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="工作流和模板区别" tabindex="-1">工作流和模板区别 <a class="header-anchor" href="#工作流和模板区别" aria-label="Permalink to &quot;工作流和模板区别&quot;">​</a></h1><p>一句话：工作流是“怎么执行”，模板是“从哪里开始复用”。</p><h2 id="工作流是什么" tabindex="-1">工作流是什么 <a class="header-anchor" href="#工作流是什么" aria-label="Permalink to &quot;工作流是什么&quot;">​</a></h2><p>工作流是一套生成流程。它规定：</p><ul><li>加载哪些模型。</li><li>提示词怎么编码。</li><li>latent 怎么生成或导入。</li><li>使用什么采样器。</li><li>是否使用 LoRA、ControlNet、参考图。</li><li>最后如何解码和保存图片。</li></ul><p>在 ComfyUI 中，工作流通常是一张节点图。节点之间的连线决定数据怎么流动。</p><h2 id="模板是什么" tabindex="-1">模板是什么 <a class="header-anchor" href="#模板是什么" aria-label="Permalink to &quot;模板是什么&quot;">​</a></h2><p>模板是可复用的起点。它可能是：</p><ul><li>一个已经搭好的工作流。</li><li>一组默认参数。</li><li>一个页面布局。</li><li>一个提示词结构。</li><li>一个项目文件夹结构。</li></ul><p>模板的重点是“复用”，不是“执行逻辑”本身。</p><h2 id="两者关系" tabindex="-1">两者关系 <a class="header-anchor" href="#两者关系" aria-label="Permalink to &quot;两者关系&quot;">​</a></h2><p>一个工作流可以作为模板保存。一个模板也可以包含工作流。</p><p>例如：</p><ul><li>文生图工作流：负责从文字生成图片。</li><li>文生图模板：预先设置好模型、尺寸、常用负向提示词和保存路径。</li></ul><h2 id="初学者应该怎么用" tabindex="-1">初学者应该怎么用 <a class="header-anchor" href="#初学者应该怎么用" aria-label="Permalink to &quot;初学者应该怎么用&quot;">​</a></h2><p>建议顺序：</p><ol><li>先用最简单的文生图工作流。</li><li>看懂每个节点负责什么。</li><li>保存一份自己的默认模板。</li><li>再扩展图生图、局部重绘、放大、参考图控制。</li></ol><h2 id="常见工作流类型" tabindex="-1">常见工作流类型 <a class="header-anchor" href="#常见工作流类型" aria-label="Permalink to &quot;常见工作流类型&quot;">​</a></h2><ul><li>文生图：文字生成图片。</li><li>图生图：基于已有图片重新生成。</li><li>Inpaint：局部重绘。</li><li>Outpaint：向画面外扩展。</li><li>Upscale：放大和细节修复。</li><li>ControlNet：通过姿势、线稿、深度图控制结构。</li><li>IP-Adapter：使用参考图影响风格或人物特征。</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>以为导入工作流就一定能跑。工作流依赖模型、节点和文件路径。</li><li>把工作流当成模型。工作流没有生成能力，模型才有。</li><li>不看缺失节点和缺失模型提示。报错通常已经指出缺什么。</li><li>一次改太多节点。调试时应该固定变量。</li></ul>',21)])])}const f=a(o,[["render",r]]);export{c as __pageData,f as default};
